\subsubsection{Visit Operation from Node to Node}
For a walker visiting a directly connected node, implementing the node-to-node traversal from Section :
\begin{align}
&\frac{
\begin{array}{c}
w \triangleright n_{\text{next}} \\
L(w) = n_{\text{curr}} \in N \\
\exists e \in E : e = (n_{\text{curr}}, n_{\text{next}}) \lor e = (n_{\text{next}}, n_{\text{curr}}) \\
A(w) = \text{active}
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [VISIT-NODE-TO-NODE]}\\
&\text{where } \sigma' = (O, N, E, W, Q[w \mapsto Q(w) \cdot \langle n_{\text{next}} \rangle], L, A, S) \nonumber
\end{align}
where \( Q[w \mapsto Q(w) \cdot \langle n_{\text{next}} \rangle] \) appends node \( n_{\text{next}} \) to walker \( w \)'s destination queue. This implements direct node-to-node traversal, which implicitly crosses the connecting edge without triggering edge abilities.

\subsubsection{Visit Operation from Node to Edge}
For a walker visiting an edge from a node, implementing the node-to-edge traversal from Section :
\begin{align}
&\frac{
\begin{array}{c}
w \triangleright e \\
e = (n_{\text{src}}, n_{\text{dst}}) \in E \\
L(w) = n_{\text{curr}} \in N \\
n_{\text{curr}} \in \{n_{\text{src}}, n_{\text{dst}}\} \\
A(w) = \text{active} \\
n_{\text{dest}} = \begin{cases} 
        n_{\text{dst}} & \text{if } n_{\text{curr}} = n_{\text{src}} \\
        n_{\text{src}} & \text{if } n_{\text{curr}} = n_{\text{dst}}
    \end{cases}
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [VISIT-NODE-TO-EDGE]}\\
&\text{where } \sigma' = (O, N, E, W, Q[w \mapsto Q(w) \cdot \langle e, n_{\text{dest}} \rangle], L, A, S) \nonumber
\end{align}
where \( Q[w \mapsto Q(w) \cdot \langle e, n_{\text{dest}} \rangle] \) appends both the edge \( e \) and its appropriate destination node to walker \( w \)'s queue. This implements the node-to-edge traversal semantics, where both the edge and its opposite endpoint are automatically queued.

\subsubsection{Visit Operation to Path}
For a walker visiting a path collection, implementing the path traversal semantics from Section :
\begin{align}
&\frac{
\begin{array}{c}
w \triangleright \mathcal{P} \\
\mathcal{P} = [p_1, p_2, \ldots, p_k] \\
L(w) = n_{\text{curr}} \in N \\
A(w) = \text{active} \\
\text{Reachable}(n_{\text{curr}}, p_1)
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [VISIT-PATH]}\\
&\text{where } \sigma' = (O, N, E, W, Q[w \mapsto Q(w) \cdot \langle p_1, p_2, \ldots, p_k \rangle], L, A, S) \nonumber
\end{align}
where:
\begin{itemize}
    \item \( \text{Reachable}(n_{\text{curr}}, p_1) \) means that either:
    \begin{itemize}
        \item If \(p_1\) is a node: \( n_{\text{curr}} = p_1 \) or there exists an edge connecting \( n_{\text{curr}} \) and \( p_1 \)
        \item If \(p_1\) is an edge: \( n_{\text{curr}} \) is an endpoint of \( p_1 \)
    \end{itemize}
    \item \( Q[w \mapsto Q(w) \cdot \langle p_1, p_2, \ldots, p_k \rangle] \) appends all elements in the path to the walker's queue
\end{itemize}

\subsubsection{Multiple Visit Operation by Direction}
For a walker visiting multiple edges based on directional filtering, supporting the directional traversal capabilities described in Section:
\begin{align}
&\frac{
\begin{array}{c}
w \triangleright \{e \in E | \text{dir}(e, n_{\text{curr}}) = d\} \\
L(w) = n_{\text{curr}} \in N \\
A(w) = \text{active} \\
d \in \{\text{outgoing}, \text{incoming}, \text{any}\} \\
E_d = \{e \in E | e \text{ connects to } n_{\text{curr}} \text{ and } \text{dir}(e, n_{\text{curr}}) = d\}
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [VISIT-DIRECTION]}\\
&\text{where } \sigma' = (O, N, E, W, Q[w \mapsto Q(w) \cdot \langle E_d \rangle], L, A, S) \nonumber
\end{align}
where:
\begin{itemize}
    \item \( d \in \{\text{outgoing}, \text{incoming}, \text{any}\} \) specifies the direction filter
    \item \( \text{dir}(e, n_{\text{curr}}) \) evaluates to \(\text{outgoing}\) if \(n_{\text{curr}} = n_{\text{src}}\) for edge \(e = (n_{\text{src}}, n_{\text{dst}})\), and \(\text{incoming}\) if \(n_{\text{curr}} = n_{\text{dst}}\)
    \item \( Q[w \mapsto Q(w) \cdot \langle E_d \rangle] \) appends the sequence of filtered edges and their destination nodes to the walker's queue
\end{itemize}

\subsubsection{Walker Movement from Node to Edge}
For a walker moving from a node to an edge in its queue after completing all abilities at the current node:
\begin{align}
&\frac{
\begin{array}{c}
Q(w) = e \cdot Q' \\
L(w) = n_{\text{curr}} \in N \\
e = (n_{\text{src}}, n_{\text{dst}}) \in E \\
n_{\text{curr}} \in \{n_{\text{src}}, n_{\text{dst}}\} \\
A(w) = \text{active} \\
\text{AbilitiesComplete}(w, n_{\text{curr}})
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [W-NODE-TO-EDGE]}\\
&\text{where } \sigma' = (O, N, E, W, Q[w \mapsto Q'], L[w \mapsto e], A, S[w, e \mapsto n_{\text{curr}}]) \nonumber
\end{align}
where:
\begin{itemize}
    \item \( Q[w \mapsto Q'] \) updates walker \( w \)'s queue by removing the first element
    \item \( L[w \mapsto e] \) updates \( w \)'s location to the edge \( e \)
    \item \( S[w, e \mapsto n_{\text{curr}}] \) records the node from which the walker entered the edge
    \item \(\text{AbilitiesComplete}(w, n_{\text{curr}})\) ensures all abilities at the current node have finished execution, following the ability execution order defined in Section
\end{itemize}

\subsubsection{Walker Movement from Edge to Node}
For a walker moving from an edge to a node in its queue after completing all abilities at the current edge:
\begin{align}
&\frac{
\begin{array}{c}
Q(w) = n_{\text{next}} \cdot Q' \\
L(w) = e \in E \\
e = (n_{\text{src}}, n_{\text{dst}}) \\
n_{\text{next}} \in \{n_{\text{src}}, n_{\text{dst}}\} \\
n_{\text{next}} \neq S(w, e) \\
A(w) = \text{active} \\
\text{AbilitiesComplete}(w, e)
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [W-EDGE-TO-NODE]}\\
&\text{where } \sigma' = (O, N, E, W, Q[w \mapsto Q'], L[w \mapsto n_{\text{next}}], A, S) \nonumber
\end{align}
where:
\begin{itemize}
    \item \( Q[w \mapsto Q'] \) updates walker \( w \)'s queue by removing the first element
    \item \( L[w \mapsto n_{\text{next}}] \) updates \( w \)'s location to the node \( n_{\text{next}} \)
    \item \(\text{AbilitiesComplete}(w, e)\) ensures all abilities at the current edge have finished execution
    \item \( n_{\text{next}} \neq S(w, e) \) ensures the walker is moving to the node opposite from where it entered the edge
\end{itemize}

\subsubsection{Edge Automatic Queue Update}
For a walker that entered an edge but doesn't have the destination node queued, implementing the automatic endpoint queueing described in Section:
\begin{align}
&\frac{
\begin{array}{c}
L(w) = e \in E \\
e = (n_{\text{src}}, n_{\text{dst}}) \\
S(w, e) = n_{\text{entry}} \\
n_{\text{dest}} = \begin{cases} 
        n_{\text{dst}} & \text{if } n_{\text{entry}} = n_{\text{src}} \\
        n_{\text{src}} & \text{if } n_{\text{entry}} = n_{\text{dst}}
    \end{cases} \\
n_{\text{dest}} \notin Q(w) \\
A(w) = \text{active}
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [EDGE-AUTO-QUEUE]}\\
&\text{where } \sigma' = (O, N, E, W, Q[w \mapsto Q(w) \cdot \langle n_{\text{dest}} \rangle], L, A, S) \nonumber
\end{align}
where the appropriate destination node is automatically appended to the walker's queue if not already present.

\subsubsection{Skip Operation}
For skipping the remaining execution at the current location and proceeding to the next location in the queue, implementing the skip statement from Section:
\begin{align}
&\frac{
\begin{array}{c}
\text{skip}(w) \\
Q(w) = l_{\text{next}} \cdot Q' \\
L(w) = l_{\text{curr}} \in N \cup E \\
A(w) = \text{active}
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [SKIP]}\\
&\text{where } \sigma' = \begin{cases} 
(O, N, E, W, Q[w \mapsto Q'], L[w \mapsto l_{\text{next}}], A, S) & \text{if } l_{\text{next}} \in N \\
(O, N, E, W, Q[w \mapsto Q'], L[w \mapsto l_{\text{next}}], A, S[w, l_{\text{next}} \mapsto l_{\text{curr}}]) & \text{if } l_{\text{next}} \in E \text{ and } l_{\text{curr}} \in N \\
\text{Error} & \text{if } l_{\text{next}} \in E \text{ and } l_{\text{curr}} \in E
\end{cases} \nonumber
\end{align}
where the walker immediately moves to the next location in its queue without executing any remaining abilities, bypassing exit abilities at the current location.

\subsubsection{Disengage Operation}
For disengaging a walker from the spatial structure, implementing the disengage statement from Section:
\begin{align}
&\frac{
\begin{array}{c}
\text{disengage}(w) \\
L(w) \in N \cup E \\
A(w) = \text{active}
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [DISENGAGE]}\\
&\text{where } \sigma' = (O, N, E, W, Q[w \mapsto \langle\rangle], L[w \mapsto \emptyset], A[w \mapsto \text{inactive}], S') \nonumber
\end{align}
where:
\begin{itemize}
    \item \( Q[w \mapsto \langle\rangle] \) clears the walker's queue
    \item \( L[w \mapsto \emptyset] \) removes the walker's location
    \item \( A[w \mapsto \text{inactive}] \) sets the walker to inactive
    \item \( S' \) is \( S \) with any mapping for \( w \) removed
\end{itemize}

\subsubsection{Queue Exhaustion}
For a walker that has completed execution at its current location and has an empty queue:
\begin{align}
&\frac{
\begin{array}{c}
Q(w) = \langle\rangle \\
L(w) = n \in N \\
A(w) = \text{active} \\
\text{AbilitiesComplete}(w, n)
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [QUEUE-EXHAUSTION-NODE]}\\
&\text{where } \sigma' = (O, N, E, W, Q, L, A[w \mapsto \text{inactive}], S) \nonumber
\end{align}
where the walker remains at its current node but transitions to an inactive state as described in Section.

\subsubsection{Node Entry Ability Activation}
For node entry abilities activating when a walker arrives:
\begin{align}
\frac{
\begin{array}{c}
L(w) = n \in N \\
A(w) = \text{active} \\
w \in \tau_{\text{walker}} \\
a \in \text{entry\_abilities}(n) \\
\text{matches}(a, \tau_{\text{walker}}) \\
\text{NotExecuted}(a, n, w)
\end{array}
}{\sigma \Rightarrow \sigma \oplus \text{execute}(a, n, w)} \text{ [N-ENTRY-ABILITY]}
\end{align}
where \( \oplus \) represents state composition after ability execution, \( \text{matches}(a, \tau_{\text{walker}}) \) indicates that ability \( a \) matches the walker type, and \(\text{NotExecuted}(a, n, w)\) ensures the ability hasn't already executed for this walker-node pair. This implements the location entry ability execution described in Section.

\subsubsection{Walker Entry Ability for Node Activation}
For walker entry abilities activating after node entry abilities have completed:
\begin{align}
\frac{
\begin{array}{c}
L(w) = n \in N \\
A(w) = \text{active} \\
n \in \tau_{\text{node}} \\
a \in \text{entry\_abilities}(w) \\
\text{matches}(a, \tau_{\text{node}}) \\
\text{NodeEntryComplete}(n, w) \\
\text{NotExecuted}(a, w, n)
\end{array}
}{\sigma \Rightarrow \sigma \oplus \text{execute}(a, w, n)} \text{ [W-ENTRY-NODE-ABILITY]}
\end{align}
where \(\text{NodeEntryComplete}(n, w)\) ensures all node entry abilities have executed before walker entry abilities begin. This implements the execution precedence from Section where location entry abilities execute before walker entry abilities.

\subsubsection{Edge Entry Ability Activation}
For edge entry abilities activating when a walker arrives:
\begin{align}
\frac{
\begin{array}{c}
L(w) = e \in E \\
A(w) = \text{active} \\
w \in \tau_{\text{walker}} \\
a \in \text{entry\_abilities}(e) \\
\text{matches}(a, \tau_{\text{walker}}) \\
\text{NotExecuted}(a, e, w)
\end{array}
}{\sigma \Rightarrow \sigma \oplus \text{execute}(a, e, w)} \text{ [E-ENTRY-ABILITY]}
\end{align}
where the edge's entry abilities are triggered when a walker enters the edge. This follows the ability execution order outlined in Section.

\subsubsection{Walker Entry Ability for Edge Activation}
For walker entry abilities activating after edge entry abilities have completed:
\begin{align}
\frac{
\begin{array}{c}
L(w) = e \in E \\
A(w) = \text{active} \\
e \in \tau_{\text{edge}} \\
a \in \text{entry\_abilities}(w) \\
\text{matches}(a, \tau_{\text{edge}}) \\
\text{EdgeEntryComplete}(e, w) \\
\text{NotExecuted}(a, w, e)
\end{array}
}{\sigma \Rightarrow \sigma \oplus \text{execute}(a, w, e)} \text{ [W-ENTRY-EDGE-ABILITY]}
\end{align}
where \(\text{EdgeEntryComplete}(e, w)\) ensures all edge entry abilities have executed before walker entry abilities begin.

\subsubsection{Walker Exit Ability from Node Activation}
For walker exit abilities activating when preparing to leave a node:
\begin{align}
\frac{
\begin{array}{c}
L(w) = n \in N \\
A(w) = \text{active} \\
Q(w) \neq \langle\rangle \\
n \in \tau_{\text{node}} \\
a \in \text{exit\_abilities}(w) \\
\text{matches}(a, \tau_{\text{node}}) \\
\text{EntryComplete}(n, w) \\
\text{NotExecuted}(a, w, n)
\end{array}
}{\sigma \Rightarrow \sigma \oplus \text{execute}(a, w, n)} \text{ [W-EXIT-NODE-ABILITY]}
\end{align}
where \(\text{EntryComplete}(n, w)\) ensures all entry abilities have executed before exit abilities begin. This implements the behavior where all entry abilities execute before any exit abilities.

\subsubsection{Node Exit Ability Activation}
For node exit abilities activating after walker exit abilities have completed:
\begin{align}
\frac{
\begin{array}{c}
L(w) = n \in N \\
A(w) = \text{active} \\
Q(w) \neq \langle\rangle \\
w \in \tau_{\text{walker}} \\
a \in \text{exit\_abilities}(n) \\
\text{matches}(a, \tau_{\text{walker}}) \\
\text{WalkerExitComplete}(w, n) \\
\text{NotExecuted}(a, n, w)
\end{array}
}{\sigma \Rightarrow \sigma \oplus \text{execute}(a, n, w)} \text{ [N-EXIT-ABILITY]}
\end{align}
where \(\text{WalkerExitComplete}(w, n)\) ensures all walker exit abilities have executed before node exit abilities begin. This implements the execution precedence where walker exit abilities execute before location exit abilities.

\subsubsection{Walker Exit Ability from Edge Activation}
For walker exit abilities activating when preparing to leave an edge:
\begin{align}
\frac{
\begin{array}{c}
L(w) = e \in E \\
A(w) = \text{active} \\
Q(w) \neq \langle\rangle \\
e \in \tau_{\text{edge}} \\
a \in \text{exit\_abilities}(w) \\
\text{matches}(a, \tau_{\text{edge}}) \\
\text{EntryComplete}(e, w) \\
\text{NotExecuted}(a, w, e)
\end{array}
}{\sigma \Rightarrow \sigma \oplus \text{execute}(a, w, e)} \text{ [W-EXIT-EDGE-ABILITY]}
\end{align}
where \(\text{EntryComplete}(e, w)\) ensures all entry abilities have executed before exit abilities begin.

\subsubsection{Edge Exit Ability Activation}
For edge exit abilities activating after walker exit abilities have completed:
\begin{align}
\frac{
\begin{array}{c}
L(w) = e \in E \\
A(w) = \text{active} \\
Q(w) \neq \langle\rangle \\
w \in \tau_{\text{walker}} \\
a \in \text{exit\_abilities}(e) \\
\text{matches}(a, \tau_{\text{walker}}) \\
\text{WalkerExitComplete}(w, e) \\
\text{NotExecuted}(a, e, w)
\end{array}
}{\sigma \Rightarrow \sigma \oplus \text{execute}(a, e, w)} \text{ [E-EXIT-ABILITY]}
\end{align}
where \(\text{WalkerExitComplete}(w, e)\) ensures all walker exit abilities have executed before edge exit abilities begin.

\begin{itemize}
    \item In a node ability \(a_{\text{node}}\) executing on node \(n\) triggered by walker \(w\):
    \begin{itemize}
        \item \(\mathbf{self} = n\) (the node instance itself)
        \item \(\mathbf{visitor} = w\) (the visiting walker)
        \item \(\mathbf{path} = Q_w\) (the walker's destination queue)
    \end{itemize}

\item In an edge ability \(a_{\text{edge}}\) executing on edge \(e\) triggered by walker \(w\):
\begin{itemize}
    \item \(\mathbf{self} = e\) (the edge instance itself)
    \item \(\mathbf{visitor} = w\) (the traversing walker)
    \item \(\mathbf{path} = Q_w\) (the walker's destination queue)
\end{itemize}

    \item In a walker ability \(a_{\text{walker}}\) executing on walker \(w\) triggered at location \(l\) (where \(l\) is either a node or edge):
    \begin{itemize}
        \item \(\mathbf{self} = w\) (the walker instance itself)
        \item \(\mathbf{here} = l\) (the current node or edge location)
        \item \(\mathbf{path} = Q_w\) (the walker's own destination queue)
    \end{itemize}
\end{itemize}

\begin{enumerate}
    \item \textbf{Direction Evaluation Function}: The function $\text{dir}(e, n)$ evaluates the direction of edge $e = (n_{\text{src}}, n_{\text{dst}})$ relative to node $n$:
    \[
    \text{dir}(e, n) = 
    \begin{cases}
    \text{outgoing} & \text{if } n = n_{\text{src}} \\
    \text{incoming} & \text{if } n = n_{\text{dst}} \\
    \text{undefined} & \text{otherwise}
    \end{cases}
    \]

\item \textbf{Traversal Path Resolution}: When a walker visits an edge from a node, the next node in its path is determined by edge orientation relative to the current node:
\[
\text{nextNode}(e, n_{\text{curr}}) = 
\begin{cases}
n_{\text{dst}} & \text{if } n_{\text{curr}} = n_{\text{src}} \\
n_{\text{src}} & \text{if } n_{\text{curr}} = n_{\text{dst}}
\end{cases}
\]

    \item \textbf{Directional Selection}: The visit statement with directional filtering enables walkers to select edges based on their orientation:
    \[
    E_{\text{filtered}} = \{e \in E \mid e \text{ connects to } n_{\text{curr}} \text{ and } \text{dir}(e, n_{\text{curr}}) \in F\}
    \]
    where $F \subseteq \{\text{outgoing}, \text{incoming}, \text{any}\}$ is the set of desired directions.
\end{enumerate}

    \item The relationship between queue operations and ability execution follows this pattern:
    \[
    \begin{array}{c}
    \forall w \in W, \forall l \in L(w) : \text{execute-all-abilities}(w, l) \prec \text{dequeue}(Q_w) \\
    \forall w \in W, \forall l' \in \text{dequeue}(Q_w) : \text{dequeue}(Q_w) \prec \text{execute-all-abilities}(w, l')
    \end{array}
    \]
    where \( \prec \) denotes execution precedence, and \(\text{execute-all-abilities}(w, l)\) represents the complete sequence of ability executions for walker \(w\) at location \(l\).
\end{enumerate}
